{
  "name": "Effito - Growth Infrastructure for Modern Care Homes",
  "description": "A premium, institutional-grade website for Effito, a company providing growth and recruitment infrastructure for care homes."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import Home from './pages/Home';
import Challenges from './pages/Challenges';
import Infrastructure from './pages/Infrastructure';
import Performance from './pages/Performance';
import HowItWorks from './pages/HowItWorks';
import WhoItsFor from './pages/WhoItsFor';
import Contact from './pages/Contact';

const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const App: React.FC = () => {
  return (
    <Router>
      <ScrollToTop />
      <div className="flex flex-col min-h-screen">
        <Header />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/challenges" element={<Challenges />} />
            <Route path="/infrastructure" element={<Infrastructure />} />
            <Route path="/performance" element={<Performance />} />
            <Route path="/how-it-works" element={<HowItWorks />} />
            <Route path="/who-its-for" element={<WhoItsFor />} />
            <Route path="/contact" element={<Contact />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
};

export default App;

import React from 'react';
import { Link, useLocation } from 'react-router-dom';

const Header: React.FC = () => {
