import React from 'react';
import { motion } from 'framer-motion';

export const OccupancyBlueprint: React.FC = () => {
  const rooms = Array.from({ length: 12 });

  return (
    <div className="relative w-full aspect-[1.2/1] bg-white rounded-xl shadow-[0_40px_100px_rgba(0,0,0,0.04)] border border-stone-100 overflow-hidden group">
      {/* Background Grid */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none" 
           style={{ backgroundImage: 'radial-gradient(#1c1c1c 1px, transparent 0)', backgroundSize: '24px 24px' }} />

      <div className="absolute inset-0 flex items-center justify-center p-8">
        <svg viewBox="0 0 400 340" className="w-full h-full drop-shadow-sm">
          {/* Base Floorplan Structure */}
          <motion.path
            initial={{ pathLength: 0, opacity: 0 }}
            animate={{ pathLength: 1, opacity: 1 }}
            transition={{ duration: 1.5, ease: "easeInOut" }}
            d="M50,100 L350,100 L350,280 L50,280 Z"
            fill="none"
            stroke="#1C1C1C"
            strokeWidth="0.5"
            strokeDasharray="4 2"
          />

          {/* Internal Walls / Grid */}
          <g className="stroke-stone-200" strokeWidth="0.5">
            <line x1="150" y1="100" x2="150" y2="280" />
            <line x1="250" y1="100" x2="250" y2="280" />
            <line x1="50" y1="160" x2="350" y2="160" />
            <line x1="50" y1="220" x2="350" y2="220" />
          </g>

          {/* Occupancy "Nodes" - The beds being filled */}
          {rooms.map((_, i) => {
            const row = Math.floor(i / 3);
            const col = i % 3;
            const x = 75 + col * 100;
            const y = 120 + row * 60;

            return (
              <motion.g key={i} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 1 + (i * 0.1) }}>
                {/* Room Identifier */}
                <text x={x-15} y={y-10} className="fill-stone-300 text-[6px] font-mono">RM-{101+i}</text>

                {/* The "Bed" or Occupancy status */}
                <motion.rect
                  x={x-10} y={y} width="20" height="20" rx="2"
                  initial={{ fill: "#F5F5F4" }}
                  animate={{ 
                    fill: i < 10 ? "#1C1C1C" : "#F5F5F4",
                    opacity: i < 10 ? [0.8, 1, 0.8] : 1
                  }}
                  transition={{ 
                    duration: 3, 
                    repeat: Infinity, 
                    delay: i * 0.2,
                    ease: "easeInOut"
                  }}
                />

                {/* If occupied, add a tiny indicator */}
                {i < 10 && (
                  <motion.circle 
                    cx={x} cy={y+10} r="2" 
                    fill="white" 
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: 1.5 + (i * 0.1) }}
                  />
                )}
              </motion.g>
            );
          })}

          {/* Infrastructure "Flow" Lines */}
          <motion.path
            d="M20,50 C60,50 80,100 100,100"
            fill="none"
            stroke="#1C1C1C"
            strokeWidth="1"
            initial={{ pathLength: 0 }}
            animate={{ pathLength: 1 }}
            transition={{ duration: 2, repeat: Infinity, repeatDelay: 1 }}
          />
          <text x="25" y="40" className="fill-slate-900 text-[8px] font-bold uppercase tracking-widest">Growth Inflow</text>
        </svg>
      </div>

      {/* Blueprint Labels */}
      <div className="absolute top-6 left-8">
        <div className="flex items-center gap-2 mb-1">
          <div className="w-1.5 h-1.5 rounded-full bg-slate-900 animate-pulse" />
          <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-900">Active Monitoring</span>
        </div>
        <span className="text-[9px] text-stone-400 font-medium">Facility ID: EF-992</span>
      </div>

      <div className="absolute bottom-6 left-8 right-8 flex justify-between items-end border-t border-stone-100 pt-4">
        <div>
          <span className="block text-[18px] font-serif text-slate-900 leading-none">92%</span>
          <span className="text-[8px] uppercase tracking-widest text-stone-400 font-bold">Current Occupancy</span>
        </div>
        <div className="text-right">
          <span className="block text-[9px] uppercase tracking-widest text-slate-900 font-bold mb-1">Effito Layer</span>
          <div className="h-1 w-20 bg-stone-100 rounded-full overflow-hidden">
            <motion.div 
              initial={{ width: 0 }}
              animate={{ width: '92%' }}
              transition={{ duration: 2, ease: "easeOut" }}
              className="h-full bg-slate-900" 
            />
          </div>
        </div>
      </div>
    </div>
  );
};

